// Before: 기본 fetch 코드 선택 후
// Cmd+K → "에러 처리와 로딩 상태 추가해줘"
const data = await fetch('/api/users');
const users = await data.json();

// After: AI가 수정한 결과
const [users, setUsers] = useState([]);
const [loading, setLoading] = useState(true);
const [error, setError] = useState(null);

useEffect(() => {
  async function fetchUsers() {
    try {
      setLoading(true);
      const res = await fetch('/api/users');
      if (!res.ok) throw new Error('Failed to fetch');
      const data = await res.json();
      setUsers(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }
  fetchUsers();
}, []);`,codeLang:"typescript"},{id:"cursor-chat",title:"Chat & Composer",icon:"💭",description:"Chat은 코드에 대한 질문과 답변, Composer는 여러 파일에 걸친 대규모 코드 생성/수정에 사용됩니다.",content:[{subtitle:"Chat (Cmd+L)",items:["코드에 대한 질문과 설명 요청","디버깅 도움 받기","특정 파일/함수를 @mention으로 참조","코드 리뷰 요청"]},{subtitle:"Composer (Cmd+I)",items:["여러 파일을 동시에 생성/수정","프로젝트 구조를 한 번에 셋업","대규모 리팩토링 작업","Agent 모드: AI가 자동으로 필요한 파일을 찾아 수정"]},{subtitle:"@mention 활용",items:["@file: 특정 파일 참조","@folder: 폴더 전체 참조","@codebase: 프로젝트 전체 검색","@web: 웹 검색 결과 참조","@docs: 공식 문서 참조"]}],code:`// Chat 활용 예시
