// 1. src/services/boardService.ts
export async function getPosts(page: number) {
  const { data, error } = await supabase
    .from('posts')
    .select('*')
    .range((page-1)*10, page*10-1)
    .order('created_at', { ascending: false });
  return { data, error };
}

// 2. src/pages/BoardList.tsx
